using SkiaSharp;
using System;
using System.Reflection;

Console.WriteLine($"SkiaSharp version: {typeof(SKPath).Assembly.GetName().Version}");

using var path1 = new SKPath();
path1.MoveTo(0, 0);
path1.LineTo(100, 0);
path1.LineTo(100, 100);
path1.Close();

using var path2 = new SKPath();
path2.MoveTo(0, 0);
path2.LineTo(100, 0);
path2.LineTo(100, 100);
path2.Close();

var methods = typeof(SKPath).GetMethods(BindingFlags.Public | BindingFlags.Instance).Where(m => m.Name == "Equals");
foreach (var m in methods)
{
    var parms = m.GetParameters();
    Console.WriteLine($"  {m.DeclaringType?.Name}.{m.Name}({string.Join(", ", parms.Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
}

var iequatable = typeof(IEquatable<SKPath>).IsAssignableFrom(typeof(SKPath));
Console.WriteLine($"IEquatable<SKPath>: {iequatable}");

var opEquals = typeof(SKPath).GetMethod("op_Equality", BindingFlags.Static | BindingFlags.Public);
Console.WriteLine($"operator==: {opEquals != null}");

Console.WriteLine($"path1.Equals(path2): {path1.Equals(path2)}");
Console.WriteLine($"path1.Equals(path1): {path1.Equals(path1)}");

var svg1 = path1.ToSvgPathData();
var svg2 = path2.ToSvgPathData();
Console.WriteLine($"SVG equal: {svg1 == svg2}");
